mapper.select:
select 
from competition c
where c.deleted_at is null

	and c.competition_year >= #{yearFrom}


	and c.competition_year <= #{yearTo}


	and (select count(*) from competition_type_tag ctt where ctt.competition_id = c.id)
		= #{categoryTypeCount}

		and exists (
			select 1 from competition_type_tag ctt
			where ctt.competition_id = c.id and ctt.type = #{categoryType}
		)


order by coalesce(c.competition_date, makedate(c.competition_year, 1)) desc,
	c.competition_date is null, c.id desc

select 
from competition c
where c.deleted_at is not null and c.deleted_at > #{cutoff}

	and c.competition_year >= #{yearFrom}


	and c.competition_year <= #{yearTo}


	and (select count(*) from competition_type_tag ctt where ctt.competition_id = c.id)
		= #{categoryTypeCount}

		and exists (
			select 1 from competition_type_tag ctt
			where ctt.competition_id = c.id and ctt.type = #{categoryType}
		)


order by c.deleted_at desc, c.id desc

select 
from competition c
where c.active_full_name = #{fullName}

mapper.update:
update competition
set active_full_name = full_name, deleted_at = null
where id = #{id} and deleted_at is not null and deleted_at > #{cutoff}

mapper.select:
select p.id, p.competition_id, p.username, p.display_name_snapshot, coalesce(u.nickname, p.display_name_snapshot) as display_name, p.create_time from competition_participant p left join `user` u on u.username = p.username where p.competition_id = #{competitionId}
and p.username in
#{username}
and 1 = 0
order by p.id

mapper.update:
update competition_award
set requires_login = #{requiresLogin}
where competition_id = #{competitionId} and id = #{awardId}

mapper.delete:
delete ca
from competition_article ca
join competition_participant p on p.id = ca.participant_id
join competition c on c.id = p.competition_id and c.deleted_at is null
join `user` u on u.username = p.username
join blog b on b.id = ca.blog_id and b.user_id = u.id
where ca.participant_id = #{participantId}
	and ca.blog_id = #{blogId}
	and p.username = #{username}

mapper.select:
select car.competition_id, car.award_id, car.participant_id,
car.profile_visible, car.profile_sort_order
from competition_award_recipient car
join competition_participant p
	on p.id = car.participant_id and p.competition_id = car.competition_id
where car.competition_id = #{competitionId}
	and car.award_id = #{awardId}
	and p.username = #{username}
for update

mapper.update:
update competition_award_recipient car
join competition_participant p
	on p.id = car.participant_id and p.competition_id = car.competition_id
set car.profile_visible = #{visible}, car.profile_sort_order = #{profileSortOrder}
where car.competition_id = #{competitionId}
	and car.award_id = #{awardId}
	and p.username = #{username}

update competition_award_recipient car
join competition_participant p
	on p.id = car.participant_id and p.competition_id = car.competition_id
join competition c on c.id = car.competition_id and c.deleted_at is null
set car.profile_sort_order = #{profileSortOrder}
where car.award_id = #{awardId}
	and p.username = #{username}
	and car.profile_visible = true
